router.get('/:id/agents', async (req, res) => {
  const project = await requireProjectAccess(req.params.id, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const configRow = await agentConfigOps.findByProjectId(req.params.id) as any;
  let storedConfig: any = {};
  if (configRow) {
    try { storedConfig = JSON.parse(configRow.config); } catch {}
  }

  const agents = AGENT_CATALOG.map((agent: any) => {
    const resolvedModel = resolveModel(req.params.id, agent.id, project.aiModel, project.aiProvider);
    const hasOverride = !!(storedConfig.agentOverrides?.[agent.id] || storedConfig.bucketModels?.[agent.bucket]);
    return {
      ...agent,
      resolvedModel,
      hasOverride,
    };
  });

  res.json({
    agents,
    bucketDefaults: PROVIDER_BUCKET_DEFAULTS[project.aiProvider] || BUCKET_DEFAULTS,
    bucketModels: storedConfig.bucketModels || {},
    agentOverrides: storedConfig.agentOverrides || {},
    projectModel: project.aiModel,
  });
});

