/**
 * Test App Helper
 *
 * Builds a lightweight Express app using the real routes and middleware,
 * backed by a temp SQLite database. Does NOT start the server, dispatcher,
 * or any background services — just the HTTP layer.
 *
 * Usage:
 *   const { app, token, projectId, cleanup } = await setupTestApp();
 *   const res = await request(app).get('/api/health');
 */

import express from 'express';
import cookieParser from 'cookie-parser';
import { v4 as uuidv4 } from 'uuid';
import { initializeDatabase, userOps, projectOps } from '../db/ops.js';
import { pgDb } from '../db/postgres.js';
import { sql } from 'drizzle-orm';
import { generateToken } from '../middleware/auth.js';

// Routes — imported directly, bypassing index.ts (no server listen / service start)
import { requestTiming } from '../middleware/request-timing.js';
import authRoutes from '../routes/auth.js';
import projectRoutes from '../routes/projects.js';
import beadsRoutes from '../routes/beads.js';
import jobRoutes from '../routes/jobs.js';
import notificationRoutes from '../routes/notifications.js';
import settingsRoutes from '../routes/settings.js';
import specRoutes from '../routes/spec.js';
import beadCommentRoutes from '../routes/bead-comments.js';

export interface TestContext {
  app: express.Express;
  /** Valid JWT for the test user */
  token: string;
  /** Test user ID */
  userId: string;
  /** Pre-created test project ID */
  projectId: string;
  /** Cleanup test data */
  cleanup: () => Promise<void>;
}

export async function setupTestApp(): Promise<TestContext> {
  // Ensure schema exists (idempotent — safe to call multiple times)
  await initializeDatabase();

  // Create a test user
  const userId = uuidv4();
  await userOps.create(
    userId,
    'test-user',
    'Test User',
    '',       // avatar_url
    'test@example.com',
    null,     // access_token
    `google-${userId}`,
  );
  // Mark onboarding complete so routes don't redirect
  await userOps.updateOnboardingCompleted(true, userId);

  // Mint a JWT
  const token = generateToken(userId);

  // Create a test project
  const projectId = uuidv4();
  await projectOps.create(
    projectId,
    userId,
    'smoke-test-project',
    '/tmp/test',
    null,    // github_repo
    'Test project for smoke tests',
    'anthropic',
    'claude-sonnet-4-20250514',
    'pr',    // merge_strategy
    false,   // github_sync_enabled
  );

  // Build a minimal Express app with real routes
  const app = express();
  app.use(requestTiming);
  app.use(express.json());
  app.use(cookieParser());

  // Mount routes at the same paths as production
  app.use('/api/auth', authRoutes);
  app.use('/api/projects', projectRoutes);
  app.use('/api/beads', beadsRoutes);
  app.use('/api/jobs', jobRoutes);
  app.use('/api/notifications', notificationRoutes);
  app.use('/api/settings', settingsRoutes);
  app.use('/api/spec', specRoutes);
  app.use('/api/beads', beadCommentRoutes);

  // Health check (same as production)
  app.get('/api/health', (_req, res) => {
    res.json({ status: 'ok', timestamp: new Date().toISOString(), version: 'test' });
  });

  // 404 catch-all
  app.use('/api', (_req, res) => {
    res.status(404).json({ error: 'Not found' });
  });

  const cleanup = async () => {
    try {
      // Delete test data (reverse order of creation for FK safety)
      await pgDb.execute(sql`DELETE FROM beads WHERE project_id = ${projectId}`);
      await pgDb.execute(sql`DELETE FROM projects WHERE id = ${projectId}`);
      await pgDb.execute(sql`DELETE FROM users WHERE id = ${userId}`);
    } catch {
      // Best effort — DB may already be closed
    }
  };

  return { app, token, userId, projectId, cleanup };
}

