1	import { agentConfigOps } from '../db/ops.js';
2	import { AGENT_CATALOG, PROVIDER_BUCKET_DEFAULTS, BUCKET_DEFAULTS, type AgentBucket } from './agent-catalog.js';
3	
4	interface StoredConfig {
5	  bucketModels?: Partial<Record<AgentBucket, string>>;
6	  agentOverrides?: Record<string, string>;
7	}
8	
9	/**
10	 * Resolve which model an agent should use for a given project.
11	 *
12	 * Resolution chain:
13	 *   1. Per-agent override (from project_agent_config)
14	 *   2. Bucket-level override (from project_agent_config)
15	 *   3. For execution bucket: project.aiModel (from projects table)
16	 *   4. Provider-specific bucket default (uses PROVIDER_BUCKET_DEFAULTS[aiProvider])
17	 *   5. Claude bucket defaults (ultimate fallback)
18	 */
19	export async function resolveModel(
20	  projectId: string,
21	  agentId: string,
22	  projectAiModel?: string,
23	  aiProvider?: string,
24	): Promise<string> {
25	  const agent = AGENT_CATALOG.find((a) => a.id === agentId);
26	  if (!agent) {
27	    return projectAiModel || 'claude-sonnet-4-20250514';
28	  }
29	
30	  const config = await loadConfig(projectId);
31	
32	  // 1. Per-agent override
33	  const agentOverride = config?.agentOverrides?.[agentId];
34	  if (agentOverride) return agentOverride;
35	
36	  // 2. Bucket-level override
37	  const bucketOverride = config?.bucketModels?.[agent.bucket];
38	  if (bucketOverride) return bucketOverride;
39	
40	  // 3. For execution bucket, fall back to project-level aiModel
41	  if (agent.bucket === 'execution' && projectAiModel) {
42	    return projectAiModel;
43	  }
44	
45	  // 4. Provider-specific bucket default
46	  const providerDefaults = aiProvider ? PROVIDER_BUCKET_DEFAULTS[aiProvider] : undefined;
47	  if (providerDefaults) {
48	    return providerDefaults[agent.bucket];
49	  }
50	
51	  // 5. Ultimate fallback — Claude bucket defaults
52	  return BUCKET_DEFAULTS[agent.bucket];
53	}
54	
55	async function loadConfig(projectId: string): Promise<StoredConfig | null> {
56	  const row = await agentConfigOps.findByProjectId(projectId) as any;
57	  if (!row) return null;
58	  try {
59	    return JSON.parse(row.config);
60	  } catch {
61	    return null;
62	  }
63	}
