interface StoredConfig {
  bucketModels?: Partial<Record<AgentBucket, string>>;
  agentOverrides?: Record<string, string>;
}

/**
 * Resolve which model an agent should use for a given project.
 *
 * Resolution chain:
 *   1. Per-agent override (from project_agent_config)
 *   2. Bucket-level override (from project_agent_config)
 *   3. For execution bucket: project.aiModel (from projects table)
 *   4. Provider-specific bucket default (uses PROVIDER_BUCKET_DEFAULTS[aiProvider])
 *   5. Claude bucket defaults (ultimate fallback)
 */
export async function resolveModel(
  projectId: string,
  agentId: string,
  projectAiModel?: string,
  aiProvider?: string,
): Promise<string> {
  const agent = AGENT_CATALOG.find((a) => a.id === agentId);
  if (!agent) {
    return projectAiModel || 'claude-sonnet-4-20250514';
  }

  const config = await loadConfig(projectId);

  // 1. Per-agent override
  const agentOverride = config?.agentOverrides?.[agentId];
  if (agentOverride) return agentOverride;

  // 2. Bucket-level override
  const bucketOverride = config?.bucketModels?.[agent.bucket];
  if (bucketOverride) return bucketOverride;

  // 3. For execution bucket, fall back to project-level aiModel
  if (agent.bucket === 'execution' && projectAiModel) {
    return projectAiModel;
  }

  // 4. Provider-specific bucket default
  const providerDefaults = aiProvider ? PROVIDER_BUCKET_DEFAULTS[aiProvider] : undefined;
  if (providerDefaults) {
    return providerDefaults[agent.bucket];
  }

  // 5. Ultimate fallback — Claude bucket defaults
  return BUCKET_DEFAULTS[agent.bucket];
}

async function loadConfig(projectId: string): Promise<StoredConfig | null> {
  const row = await agentConfigOps.findByProjectId(projectId) as any;
  if (!row) return null;
  try {
    return JSON.parse(row.config);
  } catch {
    return null;
  }
}

export type AgentBucket = 'thinking' | 'analysing' | 'execution';

export interface AgentEntry {
  id: string;
  name: string;
  service: string;
  bucket: AgentBucket;
  description: string;
  defaultModel: string;
}

export const AGENT_CATALOG: AgentEntry[] = [
  {
    id: 'project-initializer',
    name: 'Project Initializer',
    service: 'project-initializer.ts',
    bucket: 'thinking',
    description: 'Analyzes repo structure and generates initial tasks when a project is first created',
    defaultModel: 'claude-sonnet-4-20250514',
  },
  {
    id: 'task-analyzer-files',
    name: 'File Selector',
    service: 'task-analyzer.ts',
    bucket: 'analysing',
    description: 'Selects the most relevant repo files to read for analyzing a task',
    defaultModel: 'claude-haiku-4-5-20251001',
  },
  {
    id: 'task-analyzer-complexity',
    name: 'Complexity Analyzer',
    service: 'task-analyzer.ts',
    bucket: 'analysing',
    description: 'Scores task complexity, identifies affected files, and generates agent instructions',
    defaultModel: 'claude-sonnet-4-5-20250929',
  },
  {
    id: 'backlog-health',
    name: 'Backlog Health',
    service: 'backlog-health.ts',
    bucket: 'analysing',
    description: 'Unified backlog analysis: functional areas, strategic themes, duplicates, quick wins, risks, and hygiene checks',
    defaultModel: 'claude-haiku-4-5-20251001',
  },
  {
    id: 'repo-analyzer',
    name: 'Repo Analyzer',
    service: 'repo-analyzer.ts',
    bucket: 'analysing',
    description: 'Analyzes repository structure, tech stack, and complexity during onboarding',
    defaultModel: 'claude-sonnet-4-20250514',
  },
  {
    id: 'project-chat',
    name: 'Project Chat',
    service: 'project-chat.ts',
    bucket: 'analysing',
    description: 'Streams context-aware chat responses about a project',
    defaultModel: 'claude-sonnet-4-20250514',
  },
  {
    id: 'drain-summary',
    name: 'Drain Summary',
    service: 'drain-manager.ts',
    bucket: 'analysing',
    description: 'Generates QA smoke test checklists after batch dispatch completes',
    defaultModel: 'claude-haiku-4-5-20251001',
  },
  {
    id: 'agent-loop',
    name: 'Agent Executor',
    service: 'agent-loop.ts',
    bucket: 'execution',
    description: 'Runs the main agent loop that edits code, runs tests, and creates PRs',
    defaultModel: 'claude-sonnet-4-20250514',
  },
];

export const PROVIDER_BUCKET_DEFAULTS: Record<string, Record<AgentBucket, string>> = {
  claude: {
    thinking: 'claude-sonnet-4-20250514',
    analysing: 'claude-haiku-4-5-20251001',
    execution: 'claude-sonnet-4-20250514',
  },
  openai: {
    thinking: 'gpt-4o',
    analysing: 'gpt-4o-mini',
    execution: 'gpt-4o',
  },
  openrouter: {
    thinking: 'openrouter/auto',
    analysing: 'openrouter/auto',
    execution: 'openrouter/auto',
  },
};

// Backward compat alias
export const BUCKET_DEFAULTS = PROVIDER_BUCKET_DEFAULTS.claude;

export function getAgentsByBucket(): Record<AgentBucket, AgentEntry[]> {
  const result: Record<AgentBucket, AgentEntry[]> = {
    thinking: [],
    analysing: [],
    execution: [],
  };
  for (const agent of AGENT_CATALOG) {
    result[agent.bucket].push(agent);
  }
  return result;
}

