describe('Agents', () => {
  it('GET /api/projects/:id/agents returns agent catalog with resolved models', async () => {
    const res = await request(ctx.app)
      .get(`/api/projects/${ctx.projectId}/agents`)
      .set(auth());
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body.agents)).toBe(true);
    expect(res.body.agents.length).toBeGreaterThan(0);

    // Every agent must have a string resolvedModel — not a Promise or object.
    // This is the exact assertion that would have caught the missing-await bug.
    for (const agent of res.body.agents) {
      expect(typeof agent.resolvedModel).toBe('string');
      expect(agent.resolvedModel.length).toBeGreaterThan(0);
      expect(agent).toHaveProperty('id');
      expect(agent).toHaveProperty('name');
      expect(agent).toHaveProperty('bucket');
      expect(typeof agent.hasOverride).toBe('boolean');
    }
  });

  it('GET /api/projects/:id/agents returns bucket defaults', async () => {
    const res = await request(ctx.app)
      .get(`/api/projects/${ctx.projectId}/agents`)
      .set(auth());
    expect(res.body).toHaveProperty('bucketDefaults');
    expect(res.body.bucketDefaults).toHaveProperty('thinking');
    expect(res.body.bucketDefaults).toHaveProperty('analysing');
    expect(res.body.bucketDefaults).toHaveProperty('execution');
    expect(res.body).toHaveProperty('projectModel');
