/**
 * API Smoke Tests
 *
 * Fast, first-layer tests that verify the API responds correctly.
 * Runs against a real Express app + temp SQLite DB. No mocks.
 */

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import request from 'supertest';
import { setupTestApp, type TestContext } from './test-app.js';

let ctx: TestContext;

beforeAll(async () => {
  ctx = await setupTestApp();
});

afterAll(() => {
  ctx?.cleanup();
});

// Helper for authenticated requests
const auth = () => ({ Authorization: `Bearer ${ctx.token}` });

// ─── Health ───────────────────────────────────────────────────────

describe('Health', () => {
  it('GET /api/health returns 200', async () => {
    const res = await request(ctx.app).get('/api/health');
    expect(res.status).toBe(200);
    expect(res.body.status).toBe('ok');
  });
});

// ─── Auth ─────────────────────────────────────────────────────────

describe('Auth', () => {
  it('returns 401 without token', async () => {
    const res = await request(ctx.app).get('/api/projects');
    expect(res.status).toBe(401);
    expect(res.body.error).toBeDefined();
  });

  it('returns 401 with bad token', async () => {
    const res = await request(ctx.app)
      .get('/api/projects')
      .set('Authorization', 'Bearer garbage-token');
    expect(res.status).toBe(401);
  });

  it('GET /api/auth/me returns user with valid token', async () => {
    const res = await request(ctx.app)
      .get('/api/auth/me')
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body.id).toBe(ctx.userId);
    expect(res.body.username).toBe('test-user');
  });
});

// ─── Projects ─────────────────────────────────────────────────────

describe('Projects', () => {
  it('GET /api/projects lists projects', async () => {
    const res = await request(ctx.app)
      .get('/api/projects')
      .set(auth());
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    expect(res.body.length).toBeGreaterThanOrEqual(1);
    expect(res.body[0]).toHaveProperty('id');
    expect(res.body[0]).toHaveProperty('name');
  });

  it('GET /api/projects/:id returns project details', async () => {
    const res = await request(ctx.app)
      .get(`/api/projects/${ctx.projectId}`)
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body.id).toBe(ctx.projectId);
    expect(res.body.name).toBe('smoke-test-project');
  });

  it('GET /api/projects/:id returns 404 for missing project', async () => {
    const res = await request(ctx.app)
      .get('/api/projects/00000000-0000-0000-0000-000000000000')
      .set(auth());
    expect([403, 404]).toContain(res.status);
  });

  it('POST /api/projects creates a project', async () => {
    const res = await request(ctx.app)
      .post('/api/projects')
      .set(auth())
      .send({ name: 'new-test-project', description: 'Created by smoke test' });
    expect(res.status).toBe(201);
    expect(res.body.name).toBe('new-test-project');
    expect(res.body.id).toBeDefined();
  });
});

// ─── Beads ────────────────────────────────────────────────────────

describe('Beads', () => {
  let beadId: string;

  it('POST /api/beads creates a bead', async () => {
    const res = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({
        projectId: ctx.projectId,
        subject: 'Smoke test bead',
        description: 'Created by smoke test',
        priority: 2,
        beadType: 'task',
      });
    expect(res.status).toBe(201);
    expect(res.body.id).toBeDefined();
    expect(res.body.subject).toBe('Smoke test bead');
    expect(res.body.status).toBe('pending');
    beadId = res.body.id;
  });

  it('GET /api/beads lists beads for project', async () => {
    const res = await request(ctx.app)
      .get(`/api/beads?projectId=${ctx.projectId}`)
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('data');
    expect(Array.isArray(res.body.data)).toBe(true);
    expect(res.body.data.length).toBeGreaterThanOrEqual(1);
  });

  it('GET /api/beads/:id returns bead details', async () => {
    const res = await request(ctx.app)
      .get(`/api/beads/${beadId}`)
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body.id).toBe(beadId);
  });

  it('PATCH /api/beads/:id updates a bead', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, subject: 'Updated smoke test bead', priority: 1 });
    expect(res.status).toBe(200);
    expect(res.body.subject).toBe('Updated smoke test bead');
    expect(res.body.priority).toBe(1);
  });

  it('PATCH /api/beads/:id transitions status', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, status: 'in_progress' });
    expect(res.status).toBe(200);
    expect(res.body.status).toBe('in_progress');
  });

  it('PATCH /api/beads/:id completes a bead', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, status: 'completed' });
    expect(res.status).toBe(200);
    expect(res.body.status).toBe('completed');
  });

  it('POST /api/beads requires projectId and subject', async () => {
    const res = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({ description: 'Missing required fields' });
    expect(res.status).toBe(400);
  });

  it('DELETE /api/beads/:id deletes a bead', async () => {
    // Create one to delete
    const createRes = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({ projectId: ctx.projectId, subject: 'To be deleted' });
    const deleteId = createRes.body.id;

    const res = await request(ctx.app)
      .delete(`/api/beads/${deleteId}?projectId=${ctx.projectId}`)
      .set(auth());
    expect(res.status).toBe(200);
  });
});

// ─── Bead Lifecycle Cascading ─────────────────────────────────────

describe('Bead Lifecycle', () => {
  it('completing a blocker unblocks the dependent bead', async () => {
    // Create two beads: blocker and dependent
    const blockerRes = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({ projectId: ctx.projectId, subject: 'Blocker bead' });
    const blockerId = blockerRes.body.id;

    const dependentRes = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({ projectId: ctx.projectId, subject: 'Dependent bead' });
    const dependentId = dependentRes.body.id;

    // Add dependency: dependent is blocked by blocker
    const depRes = await request(ctx.app)
      .post(`/api/beads/${dependentId}/dependencies`)
      .set(auth())
      .send({ projectId: ctx.projectId, blockedBy: blockerId });
    expect(depRes.status).toBe(200);

    // Verify dependent is blocked
    const blockedRes = await request(ctx.app)
      .get(`/api/beads/${dependentId}`)
      .set(auth());
    expect(blockedRes.body.status).toBe('blocked');

    // Complete the blocker
    await request(ctx.app)
      .patch(`/api/beads/${blockerId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, status: 'in_progress' });
    await request(ctx.app)
      .patch(`/api/beads/${blockerId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, status: 'completed' });

    // Verify dependent is unblocked (should be pending now)
    const unblockedRes = await request(ctx.app)
      .get(`/api/beads/${dependentId}`)
      .set(auth());
    expect(unblockedRes.body.status).toBe('pending');
  });
});

// ─── Jobs ─────────────────────────────────────────────────────────

describe('Jobs', () => {
  it('GET /api/jobs lists jobs', async () => {
    const res = await request(ctx.app)
      .get(`/api/jobs?projectId=${ctx.projectId}`)
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('data');
    expect(Array.isArray(res.body.data)).toBe(true);
  });

  it('GET /api/jobs/stats returns stats', async () => {
    const res = await request(ctx.app)
      .get('/api/jobs/stats')
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('queued');
    expect(res.body).toHaveProperty('running');
  });
});

// ─── Notifications ────────────────────────────────────────────────

describe('Notifications', () => {
  it('GET /api/notifications returns list', async () => {
    const res = await request(ctx.app)
      .get('/api/notifications')
      .set(auth());
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
  });

  it('GET /api/notifications/unread-count returns count', async () => {
    const res = await request(ctx.app)
      .get('/api/notifications/unread-count')
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('count');
    expect(typeof res.body.count).toBe('number');
  });
});

// ─── Settings ─────────────────────────────────────────────────────

describe('Settings', () => {
  it('GET /api/settings returns settings', async () => {
    const res = await request(ctx.app)
      .get('/api/settings')
      .set(auth());
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('settings');
    expect(typeof res.body.settings).toBe('object');
  });
});

// ─── 404 ──────────────────────────────────────────────────────────

describe('404 handling', () => {
  it('returns 404 for unknown API routes', async () => {
    const res = await request(ctx.app)
      .get('/api/nonexistent')
      .set(auth());
    expect(res.status).toBe(404);
    expect(res.body.error).toBe('Not found');
  });
});

