import { Router } from 'express';
import { requireAuth } from '../middleware/auth.js';
import { validate } from '../middleware/validate.js';
import { MemoryContentBody, CreateSessionBody, SessionListQuery } from '../schemas/index.js';
import { requireProjectAccess, requirePermission } from '../middleware/project-access.js';
import { memoryService } from '../services/memory.js';
import { logActivity } from '../services/activity-logger.js';

const router = Router();

// All routes require authentication
router.use(requireAuth);

// Get all project memory
router.get('/project/:projectId', async (req, res) => {
  const { projectId } = req.params;
  const { key } = req.query;

  const project = requireProjectAccess(projectId, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  try {
    const memory = await memoryService.getProjectMemory(
      projectId,
      typeof key === 'string' ? key : undefined
    );
    res.json(memory);
  } catch (error) {
    console.error('Failed to get project memory:', error);
    res.status(500).json({ error: 'Failed to get project memory' });
  }
});

// Update project memory
router.put('/project/:projectId/:key', validate({ body: MemoryContentBody }), async (req, res) => {
  const projectId = req.params.projectId as string;
  const key = req.params.key as string;
  const { content } = req.body as MemoryContentBody;

  const project = requirePermission(projectId, req.user!.id, 'manage_memory');
  if (!project) {
    return res.status(403).json({ error: 'manage_memory permission required' });
  }

  try {
    const memory = await memoryService.updateProjectMemory(projectId, key, content, req.user!.id);

    logActivity({
      projectId,
      actorId: req.user!.id,
      actorType: 'user',
      action: 'memory.updated',
      targetType: 'memory',
      targetId: key,
      metadata: { key },
    });

    res.json(memory);
  } catch (error) {
    console.error('Failed to update project memory:', error);
    res.status(500).json({ error: 'Failed to update project memory' });
  }
});

// Delete project memory
router.delete('/project/:projectId/:key', async (req, res) => {
  const { projectId, key } = req.params;

  const project = requirePermission(projectId, req.user!.id, 'manage_memory');
  if (!project) {
    return res.status(403).json({ error: 'manage_memory permission required' });
  }

  try {
    await memoryService.deleteProjectMemory(projectId, key);
    res.status(204).send();
  } catch (error) {
    console.error('Failed to delete project memory:', error);
    res.status(500).json({ error: 'Failed to delete project memory' });
  }
});

// Get global memory
router.get('/global', async (req, res) => {
  const { key } = req.query;

  try {
    const memory = await memoryService.getGlobalMemory(
      req.user!.id,
      typeof key === 'string' ? key : undefined
    );
    res.json(memory);
  } catch (error) {
    console.error('Failed to get global memory:', error);
    res.status(500).json({ error: 'Failed to get global memory' });
  }
});

// Update global memory
router.put('/global/:key', validate({ body: MemoryContentBody }), async (req, res) => {
  const key = req.params.key as string;
  const { content } = req.body as MemoryContentBody;

  try {
    const memory = await memoryService.updateGlobalMemory(req.user!.id, key, content);
    res.json(memory);
  } catch (error) {
    console.error('Failed to update global memory:', error);
    res.status(500).json({ error: 'Failed to update global memory' });
  }
});

// Delete global memory
router.delete('/global/:key', async (req, res) => {
  const { key } = req.params;

  try {
    await memoryService.deleteGlobalMemory(req.user!.id, key);
    res.status(204).send();
  } catch (error) {
    console.error('Failed to delete global memory:', error);
    res.status(500).json({ error: 'Failed to delete global memory' });
  }
});

// Get agent context for a project
router.get('/context/:projectId', async (req, res) => {
  const { projectId } = req.params;

  const project = await requireProjectAccess(projectId, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  try {
    const context = await memoryService.buildAgentContext(projectId, project.path);
    res.json(context);
  } catch (error) {
    console.error('Failed to build agent context:', error);
    res.status(500).json({ error: 'Failed to build agent context' });
  }
});

// Get sessions for a project
router.get('/sessions/:projectId', validate({ query: SessionListQuery }), async (req, res) => {
  const projectId = req.params.projectId as string;
  const { limit } = req.query as unknown as SessionListQuery;

  const project = requireProjectAccess(projectId, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  try {
    const sessions = await memoryService.getRecentSessions(projectId, limit);
    res.json(sessions);
  } catch (error) {
    console.error('Failed to get sessions:', error);
    res.status(500).json({ error: 'Failed to get sessions' });
  }
});

// Save session summary
router.post('/sessions/:projectId', validate({ body: CreateSessionBody }), async (req, res) => {
  const projectId = req.params.projectId as string;
  const { summary, contextUsed } = req.body as CreateSessionBody;

  const project = requirePermission(projectId, req.user!.id, 'manage_memory');
  if (!project) {
    return res.status(403).json({ error: 'manage_memory permission required' });
  }

  try {
    const session = await memoryService.saveSessionSummary(projectId, summary, contextUsed);
    res.status(201).json(session);
  } catch (error) {
    console.error('Failed to save session:', error);
    res.status(500).json({ error: 'Failed to save session' });
  }
});

export default router;

import { v4 as uuidv4 } from 'uuid';
import { beadOps } from '../db/ops.js';
import { logActivity } from './activity-logger.js';
import { projectEvents } from './project-events.js';
import { getProvider } from './ai-providers/index.js';

const MAX_THREAD_CHARS = 30_000;

const EXTRACTION_PROMPT = `You are an action item extractor. Given an email thread, identify concrete action items — tasks that someone needs to do.

For each action item, return:
- title: A concise task title (imperative mood, e.g. "Review Q3 budget proposal")
- description: The relevant email context that prompted this action item (1-3 sentences)
- suggestedAssignee: The name or email of who should do it, based on the thread
- priority: 0 (none) to 4 (urgent), based on language urgency and deadlines
- reasoning: One sentence explaining why this is an action item

Rules:
- Only extract genuine action items, not FYIs or acknowledgments
- If no action items exist, return an empty array
- Keep titles under 80 characters
- Include enough context in description for someone unfamiliar with the thread

Return ONLY valid JSON: { "summary": "one-line thread summary", "items": [...] }`;

interface EmailMessage {
  sender: string;
  email: string;
  timestamp: string;
  body: string;
}

export interface EmailExtractRequest {
  projectId: string;
  subject: string;
  participants: string[];
  messages: EmailMessage[];
  threadId?: string;
}

interface ActionItem {
  title: string;
  description: string;
  suggestedAssignee: string;
  priority: number;
  reasoning: string;
}

function buildThreadContent(messages: EmailMessage[]): string {
  const formatted = messages.map(
    (m) => `From: ${m.sender} <${m.email}> (${m.timestamp})\n${m.body}`
  );

  let content = '';
  let truncated = false;
  const chunks: string[] = [];
  for (let i = formatted.length - 1; i >= 0; i--) {
    const next = formatted[i];
    if (content.length + next.length + 5 > MAX_THREAD_CHARS && chunks.length > 0) {
      truncated = true;
      break;
    }
    chunks.push(next);
    content += next;
  }
  chunks.reverse();

  const prefix = truncated
    ? `[Thread truncated — showing ${chunks.length} of ${formatted.length} most recent messages]\n\n`
    : '';
  return prefix + chunks.join('\n---\n');
}

export async function extractAndCreateBeads(
  request: EmailExtractRequest,
  actorId: string
): Promise<void> {
  const { projectId, subject, participants, messages } = request;

  try {
    const threadContent = buildThreadContent(messages);

    const userMessage = `Subject: ${subject}
Participants: ${participants.join(', ')}

Thread:
${threadContent}`;

    console.log('[EmailExtractor] Calling Claude for extraction:', subject);

    const provider = getProvider('claude');
    const text = await provider.complete({
      model: 'claude-sonnet-4-20250514',
      system: EXTRACTION_PROMPT,
      prompt: userMessage,
      maxTokens: 2048,
    });

    const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/) ?? [null, text];
    const parsed = JSON.parse(jsonMatch[1]!.trim());

    const items: ActionItem[] = (parsed.items ?? []).map((item: ActionItem) => ({
      ...item,
      priority: Math.min(4, Math.max(0, item.priority ?? 2)),
    }));

    console.log(`[EmailExtractor] Found ${items.length} action items for: ${subject}`);

    for (const item of items) {
      const id = uuidv4();
      const description = `${item.description}\n\n---\n_From email: "${subject}"_\n_Suggested assignee: ${item.suggestedAssignee}_\n_Reasoning: ${item.reasoning}_`;

      await beadOps.create(
        id,
        projectId,
        item.title,
        description,
        'pending',
        item.priority,
        null,  // owner
        '[]',  // blocked_by
        '[]',  // blocks
        null,  // github_issue_number
        null,  // github_issue_url
        null,  // local_bead_id
        null,  // local_synced_at
        null,  // parent_bead_id
        'task', // bead_type
        null   // pre_instructions
      );

      logActivity({
        projectId,
        actorId,
        actorType: 'system',
        action: 'bead.created',
        targetType: 'bead',
        targetId: id,
        metadata: {
          subject: item.title,
          beadType: 'task',
          source: 'email-extract',
          emailSubject: subject,
        },
      });
    }

    if (items.length > 0) {
      projectEvents.emit('change', { type: 'beads:changed', projectId });
    }

    console.log(`[EmailExtractor] Created ${items.length} beads for: ${subject}`);
  } catch (error) {
    console.error('[EmailExtractor] Failed to extract/create beads:', error);
  }
}

