/**
 * GitHub Puller — on-demand inbound sync from GitHub Issues → beads.
 *
 * Pulls fresh GitHub state when a user views a project's tasks,
 * with a 60-second cache to avoid redundant API calls.
 */

import { v4 as uuidv4 } from 'uuid';
import { beadOps, beadSyncStateOps, projectOps, githubSyncOps } from '../db/ops.js';
import { githubSyncService } from './github-sync.js';
import { githubService } from './github.js';
import { mapGitHubStatus, extractPriority } from './sync-utils.js';
import { transitionStatus } from './bead-lifecycle.js';
import { resolveGitHubToken } from './github-app.js';

const CACHE_TTL_MS = 300_000; // 5 minutes

export interface PullResult {
  pulled: number;
  created: number;
  updated: number;
  cached: boolean;
}

class GitHubPuller {
  /**
   * Pull GitHub Issues into beads if stale (> 60s since last pull).
   * Call this before returning beads to the user.
   */
  async pullIfStale(
    userId: string,
    projectId: string,
    force = false
  ): Promise<PullResult> {
    const result: PullResult = { pulled: 0, created: 0, updated: 0, cached: false };

    const project = await projectOps.findById(projectId) as any;
    if (!project?.githubRepo) return result;

    // Check credentials (installation or OAuth)
    const resolved = await resolveGitHubToken(userId, project.githubRepo);
    if (!resolved) return result;

    // Check cache
    if (!force) {
      const syncState = await beadSyncStateOps.findByProjectId(projectId) as any;
      if (syncState?.githubSyncedAt) {
        const lastSync = new Date(syncState.githubSyncedAt).getTime();
        if (Date.now() - lastSync < CACHE_TTL_MS) {
          return { ...result, cached: true };
        }
      }
    }

    const [owner, repo] = project.githubRepo.split('/');
    if (!owner || !repo) return result;

    try {
      // Fetch issues updated since last sync
      const syncState2 = await beadSyncStateOps.findByProjectId(projectId) as any;
      const since = syncState2?.githubSyncedAt ? new Date(syncState2.githubSyncedAt).toISOString() : undefined;

      const issues = await this.fetchIssues(userId, owner, repo, since);
      result.pulled = issues.length;

      for (const issue of issues) {
        try {
          // Try to find existing bead by github_issue_number
          const existing = await beadOps.findByGitHubIssue(projectId, issue.number) as any;

          if (existing) {
            // Update existing bead if GitHub state differs
            const ghStatus = mapGitHubStatus(issue.state, issue.labels);
            if (existing.status !== ghStatus) {
              transitionStatus(existing.id, ghStatus, {
                source: 'github-pull',
                force: true,
                projectId,
              });
              result.updated++;
            }
            // Update title/body if changed
            if (existing.subject !== issue.title || (existing.description || '') !== (issue.body || '')) {
              await beadOps.update(
                issue.title,
                issue.body || '',
                ghStatus,
                extractPriority(issue.labels),
                issue.assignee?.login || existing.owner,
                existing.blockedBy,
                existing.blocks,
                existing.preInstructions || null,
                existing.id
              );
              result.updated++;
            }
          } else {
            // Import as new bead
            await githubSyncService.importIssueAsBead(projectId, issue as any);
            result.created++;
          }
        } catch (err) {
          console.warn(`[GitHubPuller] Failed to process issue #${issue.number}:`, err);
        }
      }

      // Second pass: reconcile relationships for issues that were created/updated
      if (result.created > 0 || result.updated > 0) {
        await this.reconcileRelationships(userId, owner, repo, projectId, issues);
      }

      // Update sync timestamp
      await this.updateSyncTimestamp(projectId);
    } catch (err) {
      console.error('[GitHubPuller] Pull failed:', err);
    }

    return result;
  }

  /**
   * Reconcile sub-issue and dependency relationships from GitHub → beads.
   * Only runs for issues that were just created/updated in this pull.
   */
  private async reconcileRelationships(
    userId: string,
    owner: string,
    repo: string,
    projectId: string,
    issues: any[]
  ): Promise<void> {
    for (const issue of issues) {
      try {
        const bead = await beadOps.findByGitHubIssue(projectId, issue.number) as any;
        if (!bead) continue;

        // Reconcile sub-issues → parent_bead_id
        const subIssues = await githubService.listSubIssues(userId, owner, repo, issue.number);
        for (const sub of subIssues) {
          const childBead = await beadOps.findByGitHubIssue(projectId, sub.number) as any;
          if (childBead && !childBead.parentBeadId) {
            await beadOps.updateFull(
              childBead.subject, childBead.description, childBead.status,
              childBead.priority, childBead.owner, childBead.blockedBy,
              childBead.blocks, childBead.preInstructions,
              bead.id,  // parent_bead_id
              childBead.beadType,
              childBead.assignedTo || null,
              childBead.dueDate || null,
              childBead.estimatedMinutes || null,
              childBead.id
            );
          }
        }

        // Reconcile dependencies → blocked_by
        const deps = await githubService.listDependencies(userId, owner, repo, issue.number);
        if (deps.length > 0) {
          const existingBlockedBy: string[] = bead.blockedBy ? JSON.parse(bead.blockedBy) : [];
          let changed = false;
          for (const dep of deps) {
            const blockerBead = await beadOps.findByGitHubIssue(projectId, dep.number) as any;
            if (blockerBead && !existingBlockedBy.includes(blockerBead.id)) {
              existingBlockedBy.push(blockerBead.id);
              changed = true;
            }
          }
          if (changed) {
            await beadOps.updateBlockedBy(JSON.stringify(existingBlockedBy), bead.id);
          }
        }
      } catch (err) {
        // Sub-issues/dependencies APIs may not be available — silently skip
        console.warn(`[GitHubPuller] Relationship reconciliation skipped for issue #${issue.number}:`, err);
        break; // If API is unavailable, skip all remaining issues
      }
    }
  }

  /** Fetch issues from GitHub, optionally since a timestamp */
  private async fetchIssues(
    userId: string,
    owner: string,
    repo: string,
    since?: string
  ): Promise<any[]> {
    // Pass since to GitHub API to avoid fetching all issues
    return githubSyncService.getIssues(userId, owner, repo, 'all', since);
  }

  /** Update the github_synced_at timestamp */
  private async updateSyncTimestamp(projectId: string): Promise<void> {
    const now = new Date().toISOString();
    const existing = await beadSyncStateOps.findByProjectId(projectId) as any;
    if (existing) {
      await beadSyncStateOps.updateGitHubSync(now, projectId);
    } else {
      await beadSyncStateOps.upsert(
        projectId,
        null,  // local_file_hash
        null,  // local_synced_at
        now,   // github_synced_at
        null,  // local_file_hash (conflict update)
        null,  // local_synced_at (conflict update)
        now    // github_synced_at (conflict update)
      );
    }
  }
}

export const githubPuller = new GitHubPuller();

