import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import jwt from 'jsonwebtoken';
import { userOps, apiTokenOps } from '../db/ops.js';

const JWT_SECRET = process.env.SESSION_SECRET || 'dev-secret-change-in-production';

export function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

export interface AuthUser {
  id: string;
  username: string;
  displayName: string;
  avatarUrl: string;
  email?: string;
  onboardingCompleted: boolean;
  systemRole?: 'admin' | null;
}

// Extend Express User type to include our AuthUser fields
declare global {
  namespace Express {
    // eslint-disable-next-line @typescript-eslint/no-empty-interface
    interface User extends AuthUser {}
  }
}

export function generateToken(userId: string, options?: {
  orgId?: string;
  sessionTtl?: number;  // hours
  authMethod?: 'google' | 'saml' | 'oidc';
}): string {
  // expiresIn in seconds — default 7 days
  const expiresIn = options?.sessionTtl
    ? options.sessionTtl * 60 * 60
    : 7 * 24 * 60 * 60;
  return jwt.sign(
    { userId, orgId: options?.orgId, authMethod: options?.authMethod },
    JWT_SECRET,
    { expiresIn }
  );
}

export function generateLongLivedToken(userId: string): string {
  return jwt.sign({ userId, scope: 'cli' }, JWT_SECRET, { expiresIn: '90d' });
}

export interface TokenPayload {
  userId: string;
  orgId?: string;
  authMethod?: string;
  scope?: string;
}

export function verifyToken(token: string): TokenPayload | null {
  try {
    return jwt.verify(token, JWT_SECRET) as TokenPayload;
  } catch {
    return null;
  }
}

async function loadUser(userId: string): Promise<AuthUser | null> {
  const user = await userOps.findById(userId) as any;
  if (!user) return null;
  return {
    id: user.id,
    username: user.username,
    displayName: user.displayName,
    avatarUrl: user.avatarUrl,
    email: user.email,
    onboardingCompleted: !!user.onboardingCompleted,
    systemRole: user.systemRole || null,
  };
}

async function touchUserInteraction(userId: string): Promise<void> {
  await userOps.updateLastInteraction(userId);
}

export function requireSystemAdmin(req: Request, res: Response, next: NextFunction) {
  if (!req.user || req.user.systemRole !== 'admin') {
    return res.status(403).json({ error: 'System admin access required' });
  }
  next();
}

export async function requireAuth(req: Request, res: Response, next: NextFunction) {
  // Check for token in cookie, Authorization header, or query param (for SSE)
  const token =
    req.cookies?.token ||
    req.headers.authorization?.replace('Bearer ', '') ||
    (typeof req.query.token === 'string' ? req.query.token : undefined);

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Try JWT first (browser sessions + legacy CLI tokens)
  const payload = verifyToken(token);
  if (payload) {
    const authUser = await loadUser(payload.userId);
    if (!authUser) {
      return res.status(401).json({ error: 'User not found' });
    }
    touchUserInteraction(authUser.id);
    req.user = authUser;
    return next();
  }

  // Try API token (hashed lookup)
  const tokenHash = hashToken(token);
  const apiToken = await apiTokenOps.findByHash(tokenHash) as any;
  if (apiToken) {
    const authUser = await loadUser(apiToken.userId);
    if (!authUser) {
      return res.status(401).json({ error: 'User not found' });
    }
    // Update last_used_at (fire and forget)
    apiTokenOps.touchLastUsed(apiToken.id);
    touchUserInteraction(authUser.id);
    req.user = authUser;
    return next();
  }

  return res.status(401).json({ error: 'Invalid or expired token' });
}

export async function optionalAuth(req: Request, res: Response, next: NextFunction) {
  const token =
    req.cookies?.token ||
    req.headers.authorization?.replace('Bearer ', '');

  if (token) {
    // Try JWT first
    const payload = verifyToken(token);
    if (payload) {
      const authUser = await loadUser(payload.userId);
      if (authUser) {
        touchUserInteraction(authUser.id);
        req.user = authUser;
      }
    } else {
      // Try API token
      const tokenHash = hashToken(token);
      const apiToken = await apiTokenOps.findByHash(tokenHash) as any;
      if (apiToken) {
        const authUser = await loadUser(apiToken.userId);
        if (authUser) {
          apiTokenOps.touchLastUsed(apiToken.id);
          touchUserInteraction(authUser.id);
          req.user = authUser;
        }
      }
    }
  }

  next();
}

