/**
 * Ready Dispatcher — background service that auto-dispatches 'ready' beads
 * for projects with auto_dispatch_ready enabled.
 *
 * Polls every 30s. For each enabled project:
 *  1. Find beads with status='ready' and sufficient automability
 *  2. Check concurrency: running jobs < auto_dispatch_max_concurrent
 *  3. Dispatch the highest-priority ready bead as an execution job
 */

import { projectOps, beadOps, agentJobOps } from '../db/ops.js';
import { jobQueue } from './job-queue.js';

const POLL_INTERVAL_MS = 30_000;

let pollTimer: NodeJS.Timeout | null = null;
let running = false;

/**
 * Start the ready-dispatcher background poller.
 */
export function startReadyDispatcher(): void {
  if (running) return;
  running = true;
  console.log('Ready dispatcher started (polling every 30s)');

  // Immediate first poll
  pollAll();

  pollTimer = setInterval(pollAll, POLL_INTERVAL_MS);
}

/**
 * Stop the ready-dispatcher.
 */
export function stopReadyDispatcher(): void {
  if (!running) return;
  running = false;

  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  console.log('Ready dispatcher stopped');
}

/**
 * Poll all projects with auto_dispatch_ready enabled.
 */
async function pollAll(): Promise<void> {
  try {
    const projects = await projectOps.findAutoDispatchEnabled() as any[];
    for (const project of projects) {
      try {
        await pollProject(project);
      } catch (err) {
        // Per-project errors shouldn't stop other projects
        console.error(`[ReadyDispatcher] Error polling project ${project.id}:`, err);
      }
    }
  } catch (err) {
    console.error('[ReadyDispatcher] Error in poll cycle:', err);
  }
}

/**
 * Check a single project for ready beads to dispatch.
 */
async function pollProject(project: any): Promise<void> {
  const maxConcurrent = project.autoDispatchMaxConcurrent || 1;
  const minAutomability = project.autoDispatchMinAutomability || 60;

  // Count currently running execution jobs for this project
  const projectJobs = await agentJobOps.findByProjectId(project.id) as any[];
  const runningCount = projectJobs.filter(
    (j: any) => (j.status === 'queued' || j.status === 'running') && j.jobType !== 'analysis' && j.jobType !== 'audit'
  ).length;

  if (runningCount >= maxConcurrent) return;

  const slotsAvailable = maxConcurrent - runningCount;

  // Find ready beads, sorted by priority then automability
  const allBeads = await beadOps.findByProjectId(project.id) as any[];
  const activeBeadIds = new Set(
    projectJobs
      .filter((j: any) => j.status === 'queued' || j.status === 'running')
      .map((j: any) => j.beadId)
      .filter(Boolean)
  );

  const readyBeads = allBeads
    .filter((b: any) => {
      if (b.status !== 'ready') return false;
      if (activeBeadIds.has(b.id)) return false;
      if ((b.automabilityScore ?? 0) < minAutomability) return false;
      return true;
    })
    .sort((a: any, b: any) =>
      a.priority - b.priority ||
      (b.automabilityScore ?? 0) - (a.automabilityScore ?? 0) ||
      String(a.createdAt).localeCompare(String(b.createdAt))
    );

  // Dispatch up to slotsAvailable beads
  const toDispatch = readyBeads.slice(0, slotsAvailable);
  for (const bead of toDispatch) {
    try {
      const prompt = bead.preInstructions || bead.description || bead.subject;
      const job = await jobQueue.createJob({
        projectId: project.id,
        beadId: bead.id,
        prompt,
        priority: bead.priority,
        dispatchedBy: project.userId,
      });
      console.log(`[ReadyDispatcher] Auto-dispatched job ${job.id} for bead ${bead.id} (${bead.subject})`);
    } catch (err) {
      console.error(`[ReadyDispatcher] Failed to dispatch bead ${bead.id}:`, err);
    }
  }
}

