/**
 * API Performance Baselines
 *
 * Measures response times across endpoint categories to understand where
 * time is spent. Uses the same test-app infrastructure as smoke tests.
 *
 * These are observational — no hard pass/fail thresholds.
 *
 * Run: npx vitest run src/__tests__/api-perf.test.ts
 *
 * Skipped in CI — designed for local profiling with low-latency DB, not
 * meaningful against a remote Postgres with network round-trip overhead.
 */

import { describe, it, beforeAll, afterAll, afterEach } from 'vitest';

import request from 'supertest';
import { setupTestApp, type TestContext } from './test-app.js';

let ctx: TestContext;

beforeAll(async () => {
  ctx = await setupTestApp();
});

afterAll(() => {
  ctx?.cleanup();
});

const auth = () => ({ Authorization: `Bearer ${ctx.token}` });

// ─── Measurement Helpers ─────────────────────────────────────────

interface TimingResult {
  endpoint: string;
  method: string;
  runs: number;
  minMs: number;
  medianMs: number;
  p95Ms: number;
  maxMs: number;
  note: string;
}

const results: TimingResult[] = [];

function parseServerTiming(res: request.Response): number | null {
  const header = res.headers['server-timing'];
  if (!header) return null;
  const match = /total;dur=([\d.]+)/.exec(header);
  return match ? parseFloat(match[1]) : null;
}

function percentile(sorted: number[], p: number): number {
  const idx = Math.ceil((p / 100) * sorted.length) - 1;
  return sorted[Math.max(0, idx)];
}

async function measure(
  endpoint: string,
  method: 'GET' | 'POST' | 'PATCH' | 'DELETE',
  opts: {
    headers?: Record<string, string>;
    body?: Record<string, unknown>;
    runs?: number;
    warmup?: number;
    note?: string;
  } = {},
): Promise<TimingResult> {
  const { headers = {}, body, runs = 20, warmup = 3, note = '' } = opts;

  // Warmup runs (discard — JIT, lazy prepared statements, etc.)
  for (let i = 0; i < warmup; i++) {
    const r = request(ctx.app)[method.toLowerCase() as 'get'](endpoint).set(headers);
    if (body) r.send(body);
    await r;
  }

  // Measurement runs
  const durations: number[] = [];
  for (let i = 0; i < runs; i++) {
    const r = request(ctx.app)[method.toLowerCase() as 'get'](endpoint).set(headers);
    if (body) r.send(body);
    const res = await r;
    const serverMs = parseServerTiming(res);
    if (serverMs !== null) {
      durations.push(serverMs);
    }
  }

  durations.sort((a, b) => a - b);

  return {
    endpoint: `${method} ${endpoint}`,
    method,
    runs: durations.length,
    minMs: durations[0] ?? 0,
    medianMs: percentile(durations, 50),
    p95Ms: percentile(durations, 95),
    maxMs: durations[durations.length - 1] ?? 0,
    note,
  };
}

// ─── Print summary after all tests ──────────────────────────────

afterAll(() => {
  if (results.length === 0) return;

  console.log('\n');
  console.log('═══════════════════════════════════════════════════════════════════════');
  console.log('  API RESPONSE TIME BASELINES (server-side, milliseconds)');
  console.log('═══════════════════════════════════════════════════════════════════════');
  console.log('');

  // Group by category
  const fmt = (n: number) => n.toFixed(2).padStart(8);

  console.log(
    '  Endpoint'.padEnd(50) +
    'Min'.padStart(9) +
    'Median'.padStart(9) +
    'P95'.padStart(9) +
    'Max'.padStart(9) +
    '  Note',
  );
  console.log('  ' + '─'.repeat(95));

  for (const r of results) {
    console.log(
      `  ${r.endpoint.padEnd(48)}` +
      fmt(r.minMs) +
      fmt(r.medianMs) +
      fmt(r.p95Ms) +
      fmt(r.maxMs) +
      `  ${r.note}`,
    );
  }

  console.log('');
  console.log('  Infrastructure notes:');
  console.log('  • These times are LOCAL (in-process supertest). Production adds:');
  console.log('    – Vercel→Railway network hop: +50-200ms');
  console.log('    – Railway shared CPU overhead: 10-100x on CPU-bound ops');
  console.log('    – TLS handshake on first connection: +50-100ms');
  console.log('    – GitHub API calls (repos endpoints): +100-500ms each');
  console.log('');
  console.log('  Software optimization candidates visible in these numbers:');
  console.log('  • Compare "health" (no auth) vs "auth/me" (auth) → auth middleware cost');
  console.log('  • Compare "auth/me" vs "projects/:id" → project access overhead');
  console.log('  • Compare GET vs POST/PATCH → SQLite write cost');
  console.log('═══════════════════════════════════════════════════════════════════════');
  console.log('');
});

// ─── Group 1: Baseline (no auth, no DB) ──────────────────────────

describe('Baseline — no auth', () => {
  it('GET /api/health', async () => {
    const r = await measure('/api/health', 'GET', {
      note: 'Pure Express, no auth, no DB',
    });
    results.push(r);
  });
});

// ─── Group 2: Auth overhead ──────────────────────────────────────

describe('Auth overhead — JWT + user lookup + DB write', () => {
  it('GET /api/auth/me', async () => {
    const r = await measure('/api/auth/me', 'GET', {
      headers: auth(),
      note: 'JWT verify + user read + touchUserInteraction write',
    });
    results.push(r);
  });

  it('GET /api/notifications/unread-count', async () => {
    const r = await measure('/api/notifications/unread-count', 'GET', {
      headers: auth(),
      note: 'Auth + minimal business logic',
    });
    results.push(r);
  });

  it('GET /api/settings', async () => {
    const r = await measure('/api/settings', 'GET', {
      headers: auth(),
      note: 'Auth + settings read',
    });
    results.push(r);
  });
});

// ─── Group 3: Auth + project access ──────────────────────────────

describe('Auth + project access — full middleware chain', () => {
  it('GET /api/projects', async () => {
    const r = await measure('/api/projects', 'GET', {
      headers: auth(),
      note: 'Auth + project list query',
    });
    results.push(r);
  });

  it('GET /api/projects/:id', async () => {
    const r = await measure(`/api/projects/${ctx.projectId}`, 'GET', {
      headers: auth(),
      note: 'Auth + project access check',
    });
    results.push(r);
  });

  it('GET /api/beads?projectId=X', async () => {
    const r = await measure(`/api/beads?projectId=${ctx.projectId}`, 'GET', {
      headers: auth(),
      note: 'Auth + project access + bead list',
    });
    results.push(r);
  });

  it('GET /api/jobs?projectId=X', async () => {
    const r = await measure(`/api/jobs?projectId=${ctx.projectId}`, 'GET', {
      headers: auth(),
      note: 'Auth + project access + job list',
    });
    results.push(r);
  });
});

// ─── Group 4: Write operations ───────────────────────────────────

describe('Write operations — SQLite write cost', () => {
  it('POST /api/beads (create)', async () => {
    const r = await measure('/api/beads', 'POST', {
      headers: auth(),
      body: {
        projectId: ctx.projectId,
        subject: 'Perf test bead',
        description: 'Created by perf test',
        beadType: 'task',
      },
      note: 'Auth + project access + INSERT',
    });
    results.push(r);
  });

  it('PATCH /api/beads/:id (update)', async () => {
    // Create a bead to update
    const createRes = await request(ctx.app)
      .post('/api/beads')
      .set(auth())
      .send({
        projectId: ctx.projectId,
        subject: 'Bead to update in perf test',
        beadType: 'task',
      });
    const beadId = createRes.body.id;

    const r = await measure(`/api/beads/${beadId}`, 'PATCH', {
      headers: auth(),
      body: { projectId: ctx.projectId, subject: 'Updated perf test bead' },
      note: 'Auth + project access + UPDATE',
    });
    results.push(r);
  });
});

// ─── Group 5: Cache effectiveness ────────────────────────────────

describe('Cache effectiveness — repeated calls', () => {
  it('10x GET /api/projects (TTL cache)', async () => {
    const r = await measure('/api/projects', 'GET', {
      headers: auth(),
      runs: 10,
      warmup: 1,
      note: 'TTL cache (5s) should serve repeats',
    });
    results.push(r);
  });

  it('10x GET /api/beads?projectId=X', async () => {
    const r = await measure(`/api/beads?projectId=${ctx.projectId}`, 'GET', {
      headers: auth(),
      runs: 10,
      warmup: 1,
      note: 'No cross-request cache for beads',
    });
    results.push(r);
  });
});

