/**
 * Bead Comments API Contract Tests
 *
 * Validates request/response shapes against Zod schemas.
 * Runs against real Express app + temp SQLite DB.
 */

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import request from 'supertest';
import { setupTestApp, type TestContext } from './test-app.js';

let ctx: TestContext;
let beadId: string;
let commentId: string;

beforeAll(async () => {
  ctx = await setupTestApp();

  // Create a bead to attach comments to
  const res = await request(ctx.app)
    .post('/api/beads')
    .set({ Authorization: `Bearer ${ctx.token}` })
    .send({
      projectId: ctx.projectId,
      subject: 'Test bead for comments',
      description: 'Used by comment contract tests',
    });
  beadId = res.body.id;
});

afterAll(() => {
  ctx?.cleanup();
});

const auth = () => ({ Authorization: `Bearer ${ctx.token}` });

describe('Bead Comments API', () => {
  // ─── POST /api/beads/:beadId/comments ───────────────────────────

  it('POST creates a comment', async () => {
    const res = await request(ctx.app)
      .post(`/api/beads/${beadId}/comments`)
      .set(auth())
      .send({ projectId: ctx.projectId, content: 'Test comment' });

    expect(res.status).toBe(201);
    expect(res.body.id).toBeDefined();
    expect(res.body.beadId).toBe(beadId);
    expect(res.body.content).toBe('Test comment');
    expect(res.body.authorType).toBe('user');
    expect(res.body.createdAt).toBeDefined();
    commentId = res.body.id;
  });

  it('POST accepts optional metadata', async () => {
    const res = await request(ctx.app)
      .post(`/api/beads/${beadId}/comments`)
      .set(auth())
      .send({ projectId: ctx.projectId, content: 'With meta', metadata: { source: 'test' } });

    expect(res.status).toBe(201);
    expect(res.body.metadata).toEqual({ source: 'test' });
  });

  it('POST rejects missing content', async () => {
    const res = await request(ctx.app)
      .post(`/api/beads/${beadId}/comments`)
      .set(auth())
      .send({ projectId: ctx.projectId });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('POST rejects missing projectId', async () => {
    const res = await request(ctx.app)
      .post(`/api/beads/${beadId}/comments`)
      .set(auth())
      .send({ content: 'No project' });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('POST rejects empty content', async () => {
    const res = await request(ctx.app)
      .post(`/api/beads/${beadId}/comments`)
      .set(auth())
      .send({ projectId: ctx.projectId, content: '' });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  // ─── GET /api/beads/:beadId/comments ────────────────────────────

  it('GET lists comments for a bead', async () => {
    const res = await request(ctx.app)
      .get(`/api/beads/${beadId}/comments`)
      .query({ projectId: ctx.projectId })
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.data).toBeDefined();
    expect(Array.isArray(res.body.data)).toBe(true);
    expect(res.body.data.length).toBeGreaterThan(0);
    expect(res.body.data[0]).toHaveProperty('id');
    expect(res.body.data[0]).toHaveProperty('content');
    expect(res.body.data[0]).toHaveProperty('authorType');
  });

  it('GET rejects missing projectId query', async () => {
    const res = await request(ctx.app)
      .get(`/api/beads/${beadId}/comments`)
      .set(auth());

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  // ─── PATCH /api/beads/:beadId/comments/:commentId ───────────────

  it('PATCH updates a comment', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}/comments/${commentId}`)
      .set(auth())
      .send({ projectId: ctx.projectId, content: 'Updated comment' });

    expect(res.status).toBe(200);
    expect(res.body.content).toBe('Updated comment');
  });

  it('PATCH rejects missing content', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}/comments/${commentId}`)
      .set(auth())
      .send({ projectId: ctx.projectId });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('PATCH returns 404 for nonexistent comment', async () => {
    const res = await request(ctx.app)
      .patch(`/api/beads/${beadId}/comments/nonexistent-id`)
      .set(auth())
      .send({ projectId: ctx.projectId, content: 'Nope' });

    expect(res.status).toBe(404);
  });

  // ─── DELETE /api/beads/:beadId/comments/:commentId ──────────────

  it('DELETE removes a comment', async () => {
    const res = await request(ctx.app)
      .delete(`/api/beads/${beadId}/comments/${commentId}`)
      .query({ projectId: ctx.projectId })
      .set(auth());

    expect(res.status).toBe(204);
  });

  it('DELETE rejects missing projectId query', async () => {
    const res = await request(ctx.app)
      .delete(`/api/beads/${beadId}/comments/${commentId}`)
      .set(auth());

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('DELETE returns 404 for nonexistent comment', async () => {
    const res = await request(ctx.app)
      .delete(`/api/beads/${beadId}/comments/nonexistent-id`)
      .query({ projectId: ctx.projectId })
      .set(auth());

    expect(res.status).toBe(404);
  });

  // ─── Auth required ──────────────────────────────────────────────

  it('returns 401 without auth', async () => {
    const res = await request(ctx.app)
      .get(`/api/beads/${beadId}/comments`)
      .query({ projectId: ctx.projectId });

    expect(res.status).toBe(401);
  });
});

