/**
 * Notifications API Contract Tests
 *
 * Validates request/response shapes against Zod schemas.
 * Runs against real Express app + temp SQLite DB.
 */

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import request from 'supertest';
import { setupTestApp, type TestContext } from './test-app.js';
import { notificationOps } from '../db/ops.js';

let ctx: TestContext;

beforeAll(async () => {
  ctx = await setupTestApp();
});

afterAll(() => {
  ctx?.cleanup();
});

const auth = () => ({ Authorization: `Bearer ${ctx.token}` });

// Helper: create a notification the same way production code does —
// via notificationOps.create(), not an HTTP route. (POST /api/notifications
// was removed; notifications are only created server-side.)
async function seedNotification(overrides: {
  type?: string;
  title?: string;
  message?: string | null;
  metadata?: Record<string, unknown> | null;
} = {}): Promise<string> {
  const id = `notif-test-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  await notificationOps.create(
    id,
    ctx.userId,
    overrides.type ?? 'info',
    overrides.title ?? 'Test notification',
    overrides.message ?? null,
    overrides.metadata ? JSON.stringify(overrides.metadata) : null,
    null, null, null,
  );
  return id;
}

describe('Notifications API', () => {
  let createdId: string;

  // ─── Seed data via notificationOps (no public POST route) ───────

  it('seeds a notification via notificationOps.create', async () => {
    createdId = await seedNotification({
      type: 'info',
      title: 'Test notification',
      message: 'Hello',
    });
    const row = await notificationOps.findById(createdId) as any;
    expect(row).toBeTruthy();
    expect(row.type).toBe('info');
    expect(row.title).toBe('Test notification');
    expect(row.message).toBe('Hello');
    expect(Boolean(row.read)).toBe(false);
  });

  it('POST /api/notifications is not exposed', async () => {
    const res = await request(ctx.app)
      .post('/api/notifications')
      .set(auth())
      .send({ type: 'info', title: 'Should not work' });

    // 404 (route removed) — must not be 201/200
    expect(res.status).toBe(404);
  });

  // ─── GET /api/notifications ─────────────────────────────────────

  it('GET returns notifications array', async () => {
    const res = await request(ctx.app)
      .get('/api/notifications')
      .set(auth());

    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    expect(res.body.length).toBeGreaterThan(0);
    expect(res.body[0]).toHaveProperty('id');
    expect(res.body[0]).toHaveProperty('type');
    expect(res.body[0]).toHaveProperty('title');
    expect(res.body[0]).toHaveProperty('read');
  });

  // ─── GET /api/notifications/unread-count ────────────────────────

  it('GET unread-count returns count', async () => {
    const res = await request(ctx.app)
      .get('/api/notifications/unread-count')
      .set(auth());

    expect(res.status).toBe(200);
    expect(typeof res.body.count).toBe('number');
    expect(res.body.count).toBeGreaterThan(0);
  });

  // ─── PATCH /api/notifications/:id/read ──────────────────────────

  it('PATCH marks notification as read', async () => {
    const res = await request(ctx.app)
      .patch(`/api/notifications/${createdId}/read`)
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  it('PATCH returns 404 for nonexistent notification', async () => {
    const res = await request(ctx.app)
      .patch('/api/notifications/nonexistent-id/read')
      .set(auth());

    expect(res.status).toBe(404);
  });

  // ─── PATCH /api/notifications/read-all ──────────────────────────

  it('PATCH read-all marks all as read', async () => {
    const res = await request(ctx.app)
      .patch('/api/notifications/read-all')
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  // ─── DELETE /api/notifications/:id ──────────────────────────────

  it('DELETE removes a notification', async () => {
    const res = await request(ctx.app)
      .delete(`/api/notifications/${createdId}`)
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  it('DELETE returns 404 for nonexistent notification', async () => {
    const res = await request(ctx.app)
      .delete('/api/notifications/nonexistent-id')
      .set(auth());

    expect(res.status).toBe(404);
  });

  // ─── Auth required ──────────────────────────────────────────────

  it('returns 401 without auth', async () => {
    const res = await request(ctx.app).get('/api/notifications');
    expect(res.status).toBe(401);
  });
});

