/**
 * Settings API Contract Tests
 *
 * Validates request/response shapes against Zod schemas.
 * Runs against real Express app + temp SQLite DB.
 */

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import request from 'supertest';
import { setupTestApp, type TestContext } from './test-app.js';

let ctx: TestContext;

beforeAll(async () => {
  ctx = await setupTestApp();
});

afterAll(() => {
  ctx?.cleanup();
});

const auth = () => ({ Authorization: `Bearer ${ctx.token}` });

describe('Settings API', () => {
  // ─── PUT /api/settings ──────────────────────────────────────────

  it('PUT saves valid settings', async () => {
    const res = await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: { theme: 'dark', language: 'en' } });

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  it('PUT rejects missing keys field', async () => {
    const res = await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({});

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('PUT rejects non-object keys', async () => {
    const res = await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: 'not-an-object' });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  it('PUT rejects non-string values in keys', async () => {
    const res = await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: { theme: 123 } });

    expect(res.status).toBe(400);
    expect(res.body.error).toBeDefined();
  });

  // ─── GET /api/settings ──────────────────────────────────────────

  it('GET returns saved settings', async () => {
    // Save first
    await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: { test_key: 'test_value' } });

    const res = await request(ctx.app)
      .get('/api/settings')
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.settings).toBeDefined();
    expect(typeof res.body.settings).toBe('object');
    expect(res.body.settings.test_key).toBe('test_value');
  });

  it('GET masks sensitive keys', async () => {
    await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: { openai_api_key: 'sk-secret123' } });

    const res = await request(ctx.app)
      .get('/api/settings')
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.settings.openai_api_key).toBe('***masked***');
  });

  // ─── DELETE /api/settings/:key ──────────────────────────────────

  it('DELETE removes a setting', async () => {
    await request(ctx.app)
      .put('/api/settings')
      .set(auth())
      .send({ keys: { delete_me: 'value' } });

    const res = await request(ctx.app)
      .delete('/api/settings/delete_me')
      .set(auth());

    expect(res.status).toBe(200);
    expect(res.body.success).toBe(true);
  });

  // ─── Auth required ──────────────────────────────────────────────

  it('returns 401 without auth', async () => {
    const res = await request(ctx.app).get('/api/settings');
    expect(res.status).toBe(401);
  });
});

